import React, { useCallback, useEffect, useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import Button from '../common/UI/Button/Button';
import { setSelectedProcess, setProcessModule, setShowMenu, resetFlowReducer, setShowSideMenu, setCompanyProcesses, setMessageBar, setPayable } from '../../reduxStore/actions/flowActions';
import cls from './DashboardMobile.module.scss';
import { getProcessById } from '../../services/processes.service';
import { getComponents, getFieldTypes } from '../../services/components.service';
import { APPEND_TO_DATA, computeFormula, getDateForm, dashboard_page_default, APP_NAME, isUserAuthorized, pagination_max, FLOWHERO, BYFLOWHERO, generateNewUUID, page_default } from '../../shared/utility';
import { store } from '../../reduxStore/store';
import { first, take } from 'rxjs/operators';
import { getAlComponentsByModuleId, getAllModules } from '../../services/module.service';
import { LogoutModal, ModalR } from '../common';
import { useProcessTaskContext, processTaskAction } from '../../context/processTask.context';

import { isMobile } from 'react-device-detect';
import { connect, useDispatch, useSelector } from 'react-redux';
import moment, { now } from 'moment';
import 'react-tabs/style/react-tabs.css';
import { resetAuthReducer } from '../../reduxStore/actions/authActions';
import { faBarsStaggered, faXmark } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import ProcessModule from './ModulesComp/ProcessModule';
import { Autoplay, Pagination, EffectCoverflow } from 'swiper/modules';
import { Swiper, SwiperSlide } from 'swiper/react';
import 'swiper/css';
import 'swiper/css/navigation';
import 'swiper/css/pagination';
import 'swiper/css/scrollbar';
import 'swiper/css/effect-coverflow';
import './DashboardMobile.css';
import CheckoutPage from './CheckoutPage/CheckoutPage';
import { getPurchases, purchase } from '../../services/payments.service';
import { getAllUsers, updateUserOptionsById } from '../../services/user.service';
import MyProfile from '../TopBar/MyProfile/MyProfile';
import { PAYMONGO_KEY } from '../../services/API_CONSTANTS';

import { register } from 'swiper/element/bundle';

const R = require('ramda');

const DashboardMobile = props => {
	register();

	const { user, companyProcesses, allModules, components, companyData, begunModule, blueprints, payable, companyUsersArray } = props;

	const [loading, setLoading] = useState(false);
	const [selectedComponent, setSelectedComponent] = useState({});
	const [userLogout, setUserLogout] = useState(false);
	const [refreshComponent, setRefreshComponent] = useState(false);
	const [showProfile, setShowProfile] = useState(false);
	const [start, setStart] = useState(false);
	const [isProcessorOnly, setIsProcessorOnly] = useState(false);
	const [navigateTo, setNavigateTo] = useState({});
	const [showModuleNavigator, setShowModuleNavigator] = useState(false);
	const [hasActiveTx, setHasActiveTx] = useState({});
	const [showPayments, setShowPayments] = useState(false);
	const [amount, setAmount] = useState(-1);
	const [invoices, setInvoices] = useState([]);
	const [showHistory, setShowHistory] = useState(false);
	const [nav, setNav] = useState(false);

	const { authenticated } = useSelector(store => store.sessionReducer);
	const [taskProcessContext, setTaskProcessContext] = useProcessTaskContext();

	const dispatch = useDispatch();
	const navigate = useNavigate();

	const { paymentID, walletID } = useParams();

	document.title = `Dashboard | ${APP_NAME} Mobile`;

	const setInitialScreen = useCallback(
		(modules, module, isProcessor) => {
			getAlComponentsByModuleId(module, APPEND_TO_DATA, dashboard_page_default, 1, false)
				.pipe(take(1))
				.subscribe({
					next: data => {
						module.lastUpdate = 0;
						module.count = data?.total ?? 0;

						store.dispatch(setMessageBar({ show: true, message: `Fetching workflows. Dashboard will update in a while`, color: 'var(--app-color-gray-dark)', rightspin: true, noTimeout: true, bottom: true }));
						getProcessById(module.procedure.id)
							.pipe(first())
							.subscribe({
								next: data => {
									setLoading(false);

									const steps_for_use = data.steps
										.filter(step => step?.options?.showStepAll == undefined || step?.options?.showStepAll == true || (step?.options?.showStepAll == false && step?.options?.showOnly?.filter(a => user.positions.map(pos => pos.id).indexOf(a) > -1).length > 0))
										.map((step, i) => {
											return { ...step, rank: i + 1 };
										});

									store.dispatch(setProcessModule(data));
									store.dispatch(setCompanyProcesses([data], APPEND_TO_DATA));
									store.dispatch(
										setProcessModule({
											...data,
											completeSteps: data.steps,
											steps: steps_for_use,
											stepIndex: isProcessor ? 0 : data?.steps?.length > 0 ? (data?.steps[0]?.component_blueprints?.filter(cb => cb.options?.asModuleList == true).length > 0 ? 1 : 0) : 1,
											module_id: module.id,
											module: modules.find(mod => mod.id === module.id),
											isUpdating: false,
										})
									);

									setTaskProcessContext({ action: processTaskAction.setCurrentStep, value: data?.steps[isProcessor ? 0 : data?.steps?.length > 0 ? (data?.steps[0]?.component_blueprints?.filter(cb => cb.options?.asModuleList == true).length > 0 ? 1 : 0) : 1] });

									setTaskProcessContext({
										action: processTaskAction.setModuleItems,
										value: selectedComponent.component_items,
									});

									setTaskProcessContext({
										action: processTaskAction.setModuleNewStepComponents,
										value: [],
									});
									setTaskProcessContext({
										action: processTaskAction.setComponents,
										value: [],
									});

									//clear all values
									begunModule?.processModule?.steps?.length > 0 && begunModule?.processModule?.steps?.filter(step => step?.component_blueprints?.filter(cb => cb.selected_fields.filter(field => (field.value = undefined))));

									getComponents(true, false)
										.pipe(take(1))
										.subscribe({
											complete: () => {
												store.dispatch(setMessageBar({ show: false, message: '' }));
												getFieldTypes().pipe(take(1)).subscribe({});
											},
										});
								},
								error: _error => { },
							});
					},
				});
		},
		[begunModule]
	);

	useEffect(() => {
		history.pushState(null, null, location.href);
		window.onpopstate = function (event) {
			history.go(1);
		};

		dispatch(setShowSideMenu(false));
		dispatch(setShowMenu(false));
	}, [showProfile]);

	useEffect(() => {
		if (authenticated) {
			if (!isMobile) {
				// navigate('/dashboard');
			}
			if (!(companyData?.status === 'trial_ended' || companyData?.status === 'inactive')) {
				if (allModules?.length === 0) {
					setLoading(true);
					getAllModules(APPEND_TO_DATA)
						.pipe(take(1))
						.subscribe({
							next: modules => {
								const modules_found = modules?.filter(mod => mod?.options?.asMobileApp === true && (user?.app?.indexOf(mod?.name) !== -1 || user?.positions?.filter(pos => mod?.options?.processors?.indexOf(pos.id) > -1)?.length > 0));

								//checks here if what modules are run
								if (modules_found?.length === 1 && modules_found?.find(mod => user?.app?.indexOf(mod?.name) !== -1)) {
									setIsProcessorOnly(false);
									setInitialScreen(modules, modules_found[0], false);
								} else {
									const processorModules = modules?.filter(mod => mod?.options?.asMobileApp === true && user?.positions?.filter(pos => mod?.options?.processors?.indexOf(pos.id) > -1)?.length > 0);
									if (modules_found.length > 1) {
										setIsProcessorOnly(true);
										setShowModuleNavigator(true);
									} else if (processorModules.length == 1) {
										setIsProcessorOnly(true);
										setInitialScreen(processorModules, processorModules[0], true);
									}
								}

								getAllUsers().pipe(take(1)).subscribe({});
							},
						});
				} else {
					const module =
						allModules?.find(mod => mod?.options?.asMobileApp === true && user?.app?.indexOf(mod?.name) !== -1) ?? allModules?.find(mod => mod?.options?.asMobileApp === true && user?.positions?.filter(pos => mod?.options?.processors?.indexOf(pos.id) > -1)?.length > 0);
					setIsProcessorOnly(user.positions.filter(pos => module?.options?.processors?.indexOf(pos.id) > -1).length > 0);
				}
			}
			if (user?.id === '') {
				dispatch(resetAuthReducer());
				dispatch(resetFlowReducer());
			}
		}
	}, [authenticated, allModules]);

	useEffect(() => {
		allModules.length > 0 &&
			allModules.filter((module, index) => {
				getAlComponentsByModuleId(module, APPEND_TO_DATA, pagination_max, 1)
					.pipe(take(1))
					.subscribe({
						next: data => {
							module.lastUpdate = now();
						},
					});
			});
	}, [allModules]);

	useEffect(() => {
		if (authenticated) {
			if (payable?.length > 0 && walletID !== undefined && paymentID === undefined) {
				payable.map((pay, index) => {
					setLoading(true);
					purchase({
						user_id: pay?.user_id,
						id: pay?.id,
						total: +pay?.amount ?? 0,
						product: pay?.product,
						notes: pay?.paymentID,
						quantity: 1,
					})
						.pipe(first())
						.subscribe({
							next: () => {

								setLoading(false);
								if (pay.paymentID === walletID) {
									setLoading(true);
									const amount = (user?.options?.credit ?? 0.00) + (+pay?.amount ?? 0);
									updateUserOptionsById(user, { ...user?.options, credit: +amount.toFixed(2) })
										.pipe(first())
										.subscribe({
											next: _data => {
												user.options = _data.options;
												setLoading(false);
											},
											error: error => { },
										});
								}

								if (index + 1 == payable.length) {
									store.dispatch(setPayable([]));
									navigate('/mobile');
								}
							},
						});
				});
			}
		}
	}, [walletID, authenticated]);

	const Navbar = useCallback(
		props => {
			const openNav = () => {
				setNav(!nav);
			};

			return (
				<div className="navbar-section">
					{props.children}

					{/* Hamburger Icon */}

					<div className="mobile-nav">
						<Button
							clear
							loading={loading}
							clicked={() => {
								if (taskProcessContext?.components?.length > 0 || taskProcessContext?.newStepComponents?.length > 0) {
									setHasActiveTx({ open: true, handler: openNav });
								} else {
									openNav();
								}
							}}
						>
							<FontAwesomeIcon icon={faBarsStaggered} className="hamb-icon" />
						</Button>
					</div>

					<div className={cls.moduleTitle}>
						<div style={{ width: '100%' }}>{`${(begunModule.processModule.module?.name ?? '').toUpperCase()}${isProcessorOnly ? '*' : ''}`} </div>
						<div style={{ width: '100%' }}>{BYFLOWHERO('10px')}</div>
					</div>

					<div className={cls.userCardContainerTop} onClick={() => setShowProfile(true)}>
						<div className={cls.userCardInnerContainer}>{user?.photo?.length > 0 && <img alt="lg" src={user.photo} className={cls.avatarUrlImg} />}</div>
					</div>

					{/* Mobile */}
					<div className={`mobile-navbar ${nav ? 'open-nav' : ''}`} style={{ width: '70%' }}>
						<div onClick={openNav} className="mobile-navbar-close">
							<FontAwesomeIcon icon={faXmark} className="hamb-icon" />
						</div>

						<ul className="mobile-navbar-links">
							{allModules.filter(mod => mod?.options?.asMobileApp === true && (user?.app?.indexOf(mod?.name) !== -1 || user?.positions?.filter(pos => mod?.options?.processors?.indexOf(pos.id) > -1)?.length > 0)).length > 1 && (
								<li>
									<a
										style={{ fontFamily: 'var(--app-text-main-font), serif' }}
										onClick={() => {
											setShowModuleNavigator(true);
											openNav();
										}}
									>
										{'Apps'}
									</a>
								</li>
							)}
							<li>
								<a
									style={{ fontFamily: 'var(--app-text-main-font), serif' }}
									onClick={() => {
										store.dispatch(
											setProcessModule({
												...begunModule.processModule,
												stepIndex: 0,
												isUpdating: false,
											})
										);
										setRefreshComponent(true);
										setTimeout(() => setRefreshComponent(false));
										setNavigateTo({});
										setStart(true);
										openNav();
									}}
								>
									{begunModule.processModule?.module?.name ?? 'List'}
								</a>
							</li>

							<li>
								<a
									style={{ fontFamily: 'var(--app-text-main-font), serif' }}
									onClick={() => {
										setShowProfile(!showProfile);
										openNav();
									}}
								>
									{'Profile'}
								</a>
							</li>

							{begunModule.processModule?.module?.options?.credits && (
								<li>
									<a
										style={{ fontFamily: 'var(--app-text-main-font), serif' }}
										onClick={() => {
											setShowPayments(true);
											openNav();
										}}
									>
										{'Wallet'}
									</a>
								</li>
							)}

							<li>
								<a
									style={{ fontFamily: 'var(--app-text-main-font), serif' }}
									onClick={() => {
										setUserLogout(true);
										openNav();
									}}
								>
									{'Logout'}
								</a>
							</li>
						</ul>
					</div>
				</div>
			);
		},
		[nav, loading, taskProcessContext]
	);

	const moduleComponentsList = module => {
		const array_to_display = R.sortWith([R.descend(R.prop('created_date'))])(components.filter(com => com.module_id === module.id));
		return array_to_display
			.filter(component => (component.component_fields?.filter(f => f.data_type_name === 'Status' && !(f.value === 'companyData.misc_info?.lock' || f.value === 'Closed' || f.value === 'Cancelled')).length > 0))
			.filter(component => component?.status !== 'Closed')
			.map((component, index) => {
				const status = component.component_fields?.find(f => f.data_type_name === 'Status')?.value;
				const uaction = component.component_fields.find(cf => cf.data_type_name === 'Action Button');
				const paymentT = component.component_fields.find(cf => cf.data_type_name === 'Payments');
				const uactionU = companyUsersArray.find(usr => usr.id === uaction?.value);
				return (
					<div
						key={index}
						className={cls.componentCard}
						style={{ border: selectedComponent?.id === component.id ? '3px dashed black' : '' }}
						app-color-variant={`${(index % 5) + 1}`}
						onClick={() => {
							const handler = () => {
								const selectedProcess = companyProcesses.find(proc => proc.id === module.procedure.id);
								setSelectedComponent(component);
								setStart(true);
								companyData.start = true;

								let component_array = [];
								selectedProcess?.steps?.length > 0 && selectedProcess?.steps?.filter(step => step?.component_blueprints?.filter(cb => cb.selected_fields.filter(field => (field.value = undefined))));
								R.uniqWith(R.eqProps('group'))(component.component_fields).map(f => {
									component_array = [...component_array, { id: f.component_blueprint_id, temp_id: f.id, selected_fields: R.filter(R.propEq('group', f.group))(component.component_fields) }];
								});

								selectedProcess.steps.filter(step => {
									step.component_blueprints.filter(cb => {
										cb.selected_fields.filter(sf => {
											const field_found = component.component_fields?.find(cf => cf.field_name === sf.field_name);
											if (field_found != undefined) {
												sf.value = field_found.value;
												sf.group = field_found.group;
											} else if (sf.data_type_name === 'Record') {
												const label_found = component.component_fields?.find(cf => cf.field_name === sf.options.name);
												if (label_found != undefined) {
													sf.value = label_found.value;
													sf.group = label_found.group;
												}
											}
										});
									});
								});

								setTaskProcessContext({
									action: processTaskAction.setComponents,
									value: component_array,
								});
								setTaskProcessContext({
									action: processTaskAction.setModuleItems,
									value: JSON.parse(JSON.stringify(component.component_items)),
								});

								const steps_for_use = selectedProcess.steps
									.filter(step => step?.options?.showStepAll == undefined || step?.options?.showStepAll == true || (step?.options?.showStepAll == false && step?.options?.showOnly?.filter(a => user.positions.map(pos => pos.id).indexOf(a) > -1).length > 0))
									.map((step, i) => {
										return { ...step, rank: i + 1 };
									});

								const authorized =
									begunModule?.processModule?.steps?.length > 0
										? begunModule?.processModule?.steps
											?.find(step => step?.component_blueprints.filter(cb => cb.selected_fields.filter(sf => sf.data_type_name === 'Status').length > 0).length > 0)
											?.component_blueprints?.find(cb => cb.selected_fields.filter(sf => sf.data_type_name === 'Status').length > 0)?.options?.showOnly
										: [];

								const authorized_for_actions =
									begunModule?.processModule?.steps?.length > 0
										? begunModule?.processModule?.steps
											?.find(step => step?.component_blueprints.filter(cb => cb.selected_fields.filter(sf => sf.data_type_name === 'Action Button').length > 0).length > 0)
											?.component_blueprints.find(cb => cb.selected_fields.filter(sf => sf.data_type_name === 'Action Button')?.length > 0)?.options?.showOnly
										: [];

								const allowStatus =
									(status === undefined && (user?.id === selectedProcess?.user_id || authorized?.filter(a => user.positions.map(pos => pos.id).indexOf(a) > -1).length > 0)) ||
									((status === undefined || status === 'New') && component?.created_by?.id === user?.id) ||
									(status !== undefined &&
										!(status === 'Closed' || status === companyData?.misc_info?.lock) &&
										authorized?.filter(a => user.positions.map(pos => pos.id).indexOf(a) > -1).length > 0 &&
										(allModules?.find(mod => mod.id === component.module_id)?.options?.strict != true || component?.created_by?.id !== user?.id)) ||
									(component?.is_complete === false && component?.created_by?.id === user?.id);

								const allowAction = isUserAuthorized(status, authorized_for_actions, component, user, begunModule, companyData);
								const userAction = component.component_fields.find(cf => cf.data_type_name === 'Action Button')?.value ?? '';

								store.dispatch(
									setProcessModule({
										...selectedProcess,
										completeSteps: selectedProcess.steps,
										steps: steps_for_use,
										stepIndex: (
											allowStatus == true && component.created_by.id === user.id && userAction ? 0 : (allowStatus && (component.created_by.id === user.id || selectedProcess.user_id === user.id)) || (allowAction && (userAction === user.id || selectedProcess.user_id === user.id))
										)
											? 1
											: 0,
										canEdit: (
											allowStatus == true && component.created_by.id === user.id && userAction ? 0 : (allowStatus && (component.created_by.id === user.id || selectedProcess.user_id === user.id)) || (allowAction && (userAction === user.id || selectedProcess.user_id === user.id))
										)
											? true
											: false,
										status: status,
										back_id: steps_for_use.length > 0 ? steps_for_use[0].id : 0,
										module_id: component.module_id,
										module: allModules?.find(mod => mod.id === component.module_id),
										isUpdating: true,
										selectedComponent: component,
										showDetail: true,
									})
								);

								setRefreshComponent(true);
								setTimeout(() => {
									setRefreshComponent(false);
									window.scrollTo({ top: 0, behavior: 'smooth' });
								});
							};

							if (selectedComponent?.id !== component.id && (taskProcessContext?.components?.length > 0 || taskProcessContext?.newStepComponents?.length > 0)) {
								setHasActiveTx({ open: true, handler: handler });
								return;
							}

							handler();
						}}
					>
						{component.title.length > 24 ? <h5>{component.title}</h5> : <h4>{component.title}</h4>}
						<div style={{ fontSize: '16px', marginBottom: '5px' }}>{uaction?.options?.action === 'status' && uaction?.value ? uaction?.value : status ? (status === 'New' && uaction ? 'New (Assigned)' : `${status}`) : 'No Status'}</div>
						<div style={{ fontSize: '12px' }}>
							{status === 'New'
								? `${paymentT ? paymentT?.value : ''}`
								: component.created_by.id !== user.id
									? `${component.created_by.first_name} ${component.created_by.last_name}`
									: uactionU
										? `${uactionU.first_name} ${uactionU.last_name}`
										: `${paymentT ? paymentT?.value : ''}`}
						</div>
						{moment(component.created_date).format('DD MMM YYYY')}
					</div>
				);
			});
	};

	const dashboardList = () => {
		let fields_to_display = [];

		allModules.filter(mod =>
			companyProcesses
				.filter(proc => mod.procedure.id === proc.id && proc.steps.length > 0 && proc?.steps?.filter(step => step.component_blueprints.filter(cb => cb.options?.asDashboard == true)))
				.filter(proc =>
					proc.steps
						.filter(st => st.component_blueprints.filter(cb => cb.options?.asDashboard == true))
						.filter(s =>
							s.component_blueprints
								.filter(c => c.options?.asDashboard == true)
								.filter(cbp =>
									cbp.selected_fields
										.filter(sf => sf.visible == true && sf.data_type_name === 'Formula')
										.map(sf => {
											if (user?.positions?.filter(pos => cbp.options?.showOnly?.includes(pos.id)).length > 0 || cbp.options?.showOnly?.length == 0 || cbp.options?.showOnly === undefined) {
												fields_to_display = [...fields_to_display, { ...sf, module_id: mod.id, procedure: proc, module: mod }];
											} else {
												fields_to_display = [...fields_to_display];
											}
										})
								)
						)
				)
		);

		if (fields_to_display.length > 0) {
			if (isMobile == true) {
				fields_to_display = fields_to_display.slice(0, 2);
			}

			const dashboard_array = fields_to_display.map((f, i) => {
				let value = f.value ?? 0;
				if (f.data_type_name === 'Formula') {
					value = computeFormula(f.options, components, [], []);
				}
				return (
					<div
						key={i}
						className={cls.dashboardCard}
						style={{ display: 'flex', flexDirection: 'column', justifyContent: 'center' }}
						app-color-variant={`${(i % 5) + 1}`}
						onClick={() => {
							store.dispatch(setShowMenu(false));
							store.dispatch(
								setProcessModule({
									...f.procedure,
									stepIndex: 0,
									module_id: f.module_id,
									module: f.module,
								})
							);

							if (f?.options?.operator === 'countdateocc') {
								setNavigateTo({ module_id: f.module_id, key: f.options.list.length > 0 ? f.options.list[0] : 'Status', value: moment(getDateForm(f?.options?.searchtext)).format('DD MMM YYYY') });
							} else {
								setNavigateTo({ module_id: f.module_id, key: f.options.list.length > 0 ? f.options.list[0] : 'Status', value: f.options.searchtext ?? '' });
							}

							store.dispatch(
								setProcessModule({
									...begunModule.processModule,
									stepIndex: 0,

									isUpdating: false,
								})
							);
							setStart(true);
							setRefreshComponent(true);
							setTimeout(() => setRefreshComponent(false));
						}}
					>
						<div style={{ fontSize: '12px' }}>{`Dashboard`}</div>
						<h3>{f.field_name}</h3>

						{value}
					</div>
				);
			});

			return dashboard_array ?? [];
		}
	};

	const graphicalComponentsList = () => {
		const module = allModules.find(mod => mod?.options?.asGraphical == true);

		if (module === undefined) {
			return [];
		}

		const array_to_display = R.sortWith([R.descend(R.prop('created_date'))])(components.filter(com => com.module_id === module.id));

		return array_to_display
			.filter(component => component.component_fields?.filter(f => f.data_type_name === 'Status' && !(f.value === companyData.misc_info?.lock || f.value === 'Closed' || f.value === 'Cancelled')).length > 0)
			.map((component, index) => {
				const imageC = component.component_fields.find(cf => cf.data_type_name === 'Link');
				return (
					<div key={index} className={cls.imageCard} onClick={() => { }}>
						{imageC && (`${imageC?.value}`?.includes('jpg') || `${imageC?.value}`?.includes('jpeg') || `${imageC?.value}`?.includes('png')) && <img alt="lg" src={imageC?.value} style={{ objectFit: 'contain', height: '160px', borderRadius: '5px' }} />}
					</div>
				);
			});
	};
	const renderCarousell = module => {
		const dashboardArray = allModules.length > 0 ? dashboardList() : [];
		const componentsArray = module ? moduleComponentsList(module) : [];
		const graphicalsArray = allModules.length > 0 ? graphicalComponentsList() : [];

		return (
			<div className={cls.center} style={{ height: dashboardArray?.length > 0 || componentsArray?.length > 0 ? '160px' : '0px', width: '90%', minWidth: '360px', backgroundColor: 'var(--app-color-gray-lightest)' }}>
				<Swiper
					slidesPerView={'auto'}
					centeredSlides={true}
					spaceBetween={10}
					initialSlide={1}
					pagination={{
						clickable: true,
						dynamicBullets: true,
					}}
					autoplay={{
						delay: 10000,
						disableOnInteraction: false,
					}}
					modules={[Autoplay, Pagination]}
					className="mySwiper"
				>
					{graphicalsArray?.length > 0 &&
						graphicalsArray.map((page, index) => {
							return (
								<SwiperSlide key={index} className={cls.swiperslide}>
									{page}
								</SwiperSlide>
							);
						})}
					{dashboardArray?.length > 0 &&
						dashboardArray.map((page, index) => {
							return (
								<SwiperSlide key={index} className={cls.swiperslide}>
									{page}
								</SwiperSlide>
							);
						})}
					{componentsArray?.length > 0 &&
						componentsArray.map((page, index) => {
							return (
								<SwiperSlide key={index} className={cls.swiperslide}>
									{page}
								</SwiperSlide>
							);
						})}
				</Swiper>
			</div>
		);
	};

	//console.log('Dashboard Mobile user', user, companyData, companyUsersArray)
	//console.log('Dashboard Mobile', components, companyProcesses, selectedComponent)
	//console.log('Dashboard Mobile ALLModules', allModules)
	// console.log('begunModule', begunModule)

	return (
		<div className={cls.center} style={{ flexDirection: 'column', alignItems: 'center' }}>
			{begunModule?.processModule?.stepIndex == undefined || begunModule?.processModule?.stepIndex < 2 ? allModules.length > 0 && <Navbar /> : <div />}

			{allModules?.length === 0 && <div style={{ display: 'flex', margin: 'auto', width: '100%', height: '500px', alignContent: 'center', alignItems: 'center', justifyItems: 'center', justifyContent: 'center' }}>{FLOWHERO('30px')}</div>}

			{begunModule?.processModule?.stepIndex == undefined || begunModule?.processModule?.stepIndex < 2 ? allModules.length > 0 && renderCarousell(begunModule?.processModule?.module ?? allModules?.find(mod => mod?.options?.asMobileApp === true)) : <br />}

			<div className={cls.host} style={{ display: companyData.status === 'inactive' ? 'none' : '' }}>
				<div className={cls.dashboardPanel} style={{ display: 'flex', margin: '0px 0 0 0' }}>
					{begunModule?.processModule?.steps?.length > 0 && blueprints.length > 0 && !refreshComponent && (
						<ProcessModule
							isProcessorOnly={isProcessorOnly}
							paymentID={paymentID}
							navigateTo={navigateTo}
							selectedComponent={selectedComponent ?? {}}
							setSelectedComponent={setSelectedComponent}
							selectedProcess={begunModule.processModule}
							onCancel={() => {
								setStart(false);
								setRefreshComponent(true);
								setTimeout(() => setRefreshComponent(false));
							}}
						/>
					)}

					{hasActiveTx && (
						<ModalR onClose={() => setHasActiveTx({})} blured={true} scrollable={true} isOpen={Object.keys(hasActiveTx).length > 0} shadowedContainerStyle={{ width: '90%' }}>
							<div className={cls.ongoingtx}>
								{`${selectedComponent?.title ?? 'A new order'} is being edited`}

								<div style={{ display: 'flex' }}>
									<Button
										style={{ width: '100px' }}
										title={'Discard'}
										clicked={() => {
											hasActiveTx.handler(!nav);
											setHasActiveTx({});
										}}
									/>
									<Button
										style={{ width: '100px' }}
										light
										title={'Resume'}
										clicked={() => {
											setHasActiveTx(false);
										}}
									/>
								</div>
								<span style={{ display: 'flex', fontSize: '12px' }}>{'Note: Discarding a transaction being updated will just discard recent changes made.'}</span>
							</div>
						</ModalR>
					)}

					{showProfile && (
						<ModalR hasCloseIcon onClose={() => setShowProfile(false)} blured={true} scrollable={true} isOpen={showProfile} shadowedContainerStyle={{ width: '100%' }}>
							<MyProfile />
						</ModalR>
					)}

					{showModuleNavigator && (
						<ModalR blured={true} scrollable={true} isOpen={showModuleNavigator} shadowedContainerStyle={{ width: '100%' }}>
							<div className={cls.searchInput}>{'Select an app to use:'}</div>

							{/* const modules_found = modules?.filter(mod => (mod?.options?.asMobileApp === true && (mod?.name === user?.app || user?.positions?.filter(pos => mod?.options?.processors?.indexOf(pos.id) > -1)?.length > 0))); */}
							<div style={{ width: 'inherit', padding: '15px' }}>
								{allModules
									.filter(mod => mod?.options?.asMobileApp === true && (user?.app?.indexOf(mod?.name) !== -1 || user?.positions?.filter(pos => mod?.options?.processors?.indexOf(pos.id) > -1)?.length > 0))
									.map((module, index) => {
										return (
											<Button
												light
												key={index}
												title={module.name}
												clicked={() => {
													setLoading(true);
													if (user?.app?.indexOf(module.name) !== -1) {
														setIsProcessorOnly(false);
														setInitialScreen(allModules, module, false);
													} else {
														setIsProcessorOnly(true);
														setInitialScreen(allModules, module, true);
													}

													setShowModuleNavigator(false);
												}}
												style={{ width: '100%' }}
											/>
										);
									})}
							</div>

							<Button
								title={'Close'}
								style={{ width: '90%', margin: 'auto' }}
								clicked={() => {
									setShowModuleNavigator(false);
								}}
							/>
						</ModalR>
					)}

					{showPayments && (
						<ModalR
							hasCloseIcon
							isOpen={showPayments}
							onClose={() => {
								setShowPayments(false);
								setAmount(-1);
							}}
							backdropColor={true}
							blured={false}
							scrollable={true}
							shadowedContainerStyle={{ width: '100%' }}
						>
							<div style={{ display: 'flex', justifyContent: 'space-between' }}>
								<h2 style={{ color: 'var(--app-color-gray-dark)' }}>{'Wallet'}</h2>
								<Button
									loading={loading}
									clear
									title={'History'}
									style={{ width: '100px', textDecoration: 'underline', marginRight: '40px' }}
									clicked={() => {
										setLoading(true);
										getPurchases()
											.pipe(first())
											.subscribe({
												next: data => {
													setLoading(false);
													setShowHistory(true);
													setInvoices(data.data);
												},
												error: () => { },
											});
									}}
								/>
							</div>

							<div className={cls.userPanelRows} style={{ height: 'auto', minHeight: '450px', marginTop: '10px', display: amount > 0 ? 'none' : '' }}>
								<div className={cls.wallet}>
									<h3 style={{ color: 'var(--app-color-gray-dark)' }}>{'Balance:'}</h3>
									<h1>Php {user?.options?.credit?.toFixed(2) ?? '0.00'}</h1>
									<div className={cls.actionsContainer}>
										<Button clear title={'Top Up'} clicked={() => setAmount(0)} style={{ backgroundColor: 'orange', color: 'white', width: '100px', display: amount > -1 ? 'none' : '' }} />
									</div>
									<div style={{ width: 'inherit', display: amount === -1 ? 'none' : '' }}>
										<h4>{'Select your denomination:'}</h4>

										<Button light title={'Php 500.00'} clicked={() => setAmount(500)} style={{ width: '100%' }} />
										<Button light title={'Php 1000.00'} clicked={() => setAmount(1000)} style={{ width: '100%' }} />
										<Button light title={'Php 2000.00'} clicked={() => setAmount(2000)} style={{ width: '100%' }} />
										<Button light title={'Php 3000.00'} clicked={() => setAmount(4000)} style={{ width: '100%' }} />
									</div>
								</div>
								<div style={{ display: showHistory ? '' : 'none' }}>
									<div className={cls.actionsContainer}>
										<h3>{'History:'}</h3>
										<Button light title={'Hide'} clicked={() => setShowHistory(false)} />
									</div>
									{invoices?.map((inv, index) => {
										return (
											<div className={cls.filtersContainer} key={index}>
												<div className={cls.actionsContainer}>
													<div>{`${inv.starts_at}`}</div>
													<div>{`${inv.stripe_product}`}</div>

													<div>{`${(+inv.stripe_price).toFixed(2)}`}</div>
												</div>
											</div>
										);
									})}
								</div>
							</div>

							{amount > 0 ? (
								<CheckoutPage
									label={' '}
									withBack={false}
									paymentPath={'wallet'}
									onClose={() => setShowPayments(false)}
									companyData={companyData}
									subscriptionInfo={{
										user_id: user.id,
										ref: user.id,
										plan_price: amount,
										currency: 'PHP',
										plan: `Credits`,
										total: amount,
										billable_users: [user],
										duration: 0,
										dlabel: 'Flowhero',
										id: generateNewUUID(),
									}}
									onError={error => {
										// setErrorPayments(true);
										// setMessage(error);
										// setIsMandatoryError(true);
										setShowPayments(false);

										// store.dispatch(
										// 	setProcessModule({
										// 		...begunModule.processModule,
										// 		stepIndex: 0,
										// 		isUpdating: false,
										// 	})
										// );
									}}
								/>
							) : (
								<>
									<p>{PAYMONGO_KEY !== '' ? `Payments by` : ``}</p>
									<img src={'https://files.readme.io/7586db8-small-paymongo_api_white.png'} style={{ backgroundColor: 'black', height: '40px', width: '160px' }} />
								</>
							)}
						</ModalR>
					)}
					{userLogout && <LogoutModal openModal={userLogout} setOpenModal={setUserLogout} />}
				</div>
			</div>
		</div>
	);
};
const mapStateToProps = store => {
	const { begunModule, allTasks, allCompletedTasks, allCompletedTasksPaginated, companyProcesses, allModules, components, companyData, companyUsersArray, blueprints, payable } = store.flowReducer;
	const { user } = store.sessionReducer;

	return { begunModule, allTasks, allCompletedTasks, allCompletedTasksPaginated, companyProcesses, allModules, components, companyData, companyUsersArray, user, blueprints, payable };
};

const mapDispatchToProps = dispatch => {
	return {
		onSetSelectedProcess: process => dispatch(setSelectedProcess(process)),
	};
};

export default connect(mapStateToProps, mapDispatchToProps)(DashboardMobile);
